public void insert()
{
    ETGACFParameters aCFParameters = ETGACFParameters::find();
    if(aCFParameters.EnablePowerBIFields == NoYes::Yes)
    {
        DimensionDefault  dimDefault = LedgerDimensionFacade::getDefaultDimensionFromLedgerDimension(this.LedgerDimension);

        if(dimDefault)
        {
            this.ETGVertical     = ETGFixedAssetFinancialsDimensions::getDimensionDisplayValue(this.DefaultDimension, aCFParameters.Vertical);
            //this.ETGSubVertical  = ETGFixedAssetFinancialsDimensions::getDimensionDisplayValue(dimDefault, "BusinessUnit");
            this.ETGCommodity    = ETGFixedAssetFinancialsDimensions::getDimensionDisplayValue(this.DefaultDimension, aCFParameters.MainCommodity);
            this.ETGSubCommodity = ETGFixedAssetFinancialsDimensions::getDimensionDisplayValue(this.DefaultDimension, aCFParameters.SubCommodity);
            this.ETGItemDim         = ETGFixedAssetFinancialsDimensions::getDimensionDisplayValue(this.DefaultDimension, aCFParameters.ItemId);
            DefaultDimensionView DefaultDimensionView;
            select * from DefaultDimensionView where DefaultDimensionView.DEFAULTDIMENSION == this.DefaultDimension
                && DefaultDimensionView.Name == aCFParameters.SubVertical;

            DimAttributeOMBusinessUnit dimAttributeOMBusinessUnit;

            select * from dimAttributeOMBusinessUnit
        where dimAttributeOMBusinessUnit.value == DefaultDimensionView.DisplayValue;


            if (dimAttributeOMBusinessUnit)
            {
                this.ETGSubVertical            = dimAttributeOMBusinessUnit.Name;
            }

        }
    }
    next insert();
}
